INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2033_L013$$, 2026, $$The M88 Heavy Equipment Recovery Combat Utility Lift and Evacuation System (HERCULES) Family of Vehicles (FoV) provides maintenance support, towing, winching, and hoisting operations to support
 battlefield recovery operations and evacuation of heavy tanks and other tracked combat vehicles. The M88A2 is the only vehicle that can provide vehicle recovery of the 70-Ton Abrams Main Battle Tank on the
 battlefield. The Combat Recovery System (CRS) program supports the critical recapitalization and Service Life Extension Program (SLEP) of M88A2 vehicles. This program enables the Army to gain improved
 operational readiness and modernizes existing vehicle systems through technology insertion and adding useful life by returning the vehicles to a like-new condition (zero hours and zero miles). SLEP allows the
 Army to maintain critical M88A2 vehicle capabilities by extending the useful life of the aged fleet.

 Additionally, provides program personnel, engineering, Engineering Change Proposals (ECPs) design, testing, hardware procurement, training and training materials, and modification work order (MWO) of
 improvements to resolve safety, reliability, operational readiness, obsolescence and vehicle recovery operation issues identified in the field and approved by the Materiel Developer and Combat Developer.$$, $$$$, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                                 Date: April 2026
