INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2034_L041$$, 2026, $$The Conventional Munitions Demilitarization Program provides for the demilitarization (demil) and disposal of conventional ammunition and missiles that are unserviceable, obsolete, or excess to need for all
 Military Services per DoDD 5160.65 and DoDI 5160.68. The program accomplishes demil using open burning/open detonation (OB/OD) processes or closed disposal technologies (CDT) with primary emphasis
 on resource recovery and recycling (R3). This program also provides technical support and services; packaging, crating, handling, and transportation (PCHT) of ammunition for demil projects at United States
 Army depots, plants and activities; commercial contracts that provide closed disposal technologies demil support and services and associated packaging, crating, handling, and transportation; and international
 operations, which include the European and Pacific Theaters.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                    Date: April 2026
