INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2034_L042$$, 2026, $$The Armament Retooling and Manufacturing Support (ARMS) program reuses idle capacity at active and inactive Government-Owned, Contractor-Operated (GOCO) Army Ammunition Plants and the GOCO
 Hawthorne Army Depot through commercialization. Congress enacted this program in the FY 1993 Defense Authorization Act (Public Law (PL) 102-484) and codified in FY 2000 (10 U.S.C. 7551-7555). ARMS
 resources are used for facility strategic reuse plans, marketing plans, building renovation and recapitalization, equipment purchase, relocation, or consolidation, as well as environmental baseline studies and site
 surveys to encourage commercial use of underutilized Army assets, to include underutilized land available for greenfield construction. The ARMS objectives include sustaining critical manufacturing capabilities
 and critical skills; reducing facility operating and maintenance costs; decreasing product cost; providing opportunities for small business; and accelerating private sector economic development, employment and
 investment. The ARMS program allows the Army to manage portions of the ammunition infrastructure as a commercial business without encumbering production operations in support of DOW Joint Warfighter
 ammunition requirements. This management concept has allowed the Army to apply overhead costs across multiple commercial contracts to reduce operating costs.

 Justification:
 FY 2027 Base procurement dollars in the amount of $3.935 million supports financial and marketing investments to attract revenue-producing tenants to locate on Government-Owned Contractor-Operated
 (GOCO) Army Ammunition Plants and the GOCO Hawthorne Army Depot. The ARMS program reduces Army cost of ownership and maintains critical munitions industrial base skills. Revenues collected will be
 utilized to reduce overhead and total annual operating costs, improve and maintain existing buildings for current tenants, and perform improvements to other vacant buildings to entice potential tenants.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                     Date: April 2026
