INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2034_L001$$, 2026, $$This budget line includes 5.56MM ALL TYPES.

 (E01100) 5.56mm Blank, M200, Single Round cartridge consists of a brass cartridge case with primer and propellant sealed with a rosette crimp. This cartridge is used for training and ceremonial purposes
 without blank firing attachment (BFA) and in M16A2/A4 Series Rifles and M4 Carbine fitted with BFA. This item is Code A, approved for service use.

 (E01101) 5.56mm Blank, M200 Linked w/M27 links f/SAW cartridge consists of a brass cartridge case with primer and propellant sealed with a rosette crimp. This cartridge is used in the M249 Squad Automatic
 Weapon (SAW) Machine Gun with a Blank Firing Adapter, and it is designed to simulate firing during training exercises. This item is Code A, approved for service use.

 (E04607) 5.56mm M855A1 Ball Cartridges and M856A1/M1201 Tracer Cartridges Enhanced Performance Round (EPR) are linked in a 4-Ball/1-Tracer configuration with the M27 link for use in the M249
 Machine Gun. The M855A1 Ball Cartridge has a steel penetrator and non-lead slug surrounded by a copper jacket. The M856A1 Tracer Cartridge is lead free and provides a visible red-light signature through its
 trajectory. The M856A1 Tracer Cartridge provides visible signature of fire out to 900 meters. The M1201 EPR Tracer Cartridge has a steel penetrator and provides a visible light signature through its trajectory
 with a limited view during its early trajectory, providing visible signature of fire out to 900 meters and a limited view visible signature, to the shooter only, for first 300 meters. This item is Code A, approved for
 service use.

 (E04608) 5.56mm Tracer, M856A1/M1201, M856A1 Single Round Bullet is lead free and provides a visible red-light signature through its trajectory. The M1201 Single Round Bullet is lead free and provides a
 visible light signature through its trajectory with a limited view during its early trajectory, providing visible signature of fire out to 900 meters and a limited view visible signature, to the shooter only, for first 300
 meters. This item is Code A, approved for service use.

 (E95200) 5.56mm, M855A1 Ball Cartridge is linked with the M27 link for use in the M249 Machine Gun. The M855A1 Ball Cartridge has a steel penetrator and non-lead slug surrounded by a copper jacket. This
 item is Code A, approved for service use.

 (E95400) 5.56mm, M855A1 Ball Cartridge has a steel penetrator and lead-free slug surrounded by a copper jacket. The cartridge is used in M16A2/A4 Rifles and M4/M4A1 Carbines. This cartridge is packed in
 10 round clips with bandoleers in standard military can pack. This item is Code A, approved for service use.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                    Date: April 2026
