INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2034_L004$$, 2026, $$This budget line includes CTG, Handgun, ALL TYPES.

 (E05218) CTG, MODULAR HANDGUN SYSTEM (MHS) AMMUNITION for the M17, and M18 (compact version) of the Modular Handgun System, and Glock 19 Gen 5 consists of five new 9MM cartridges -
 Ball M1152, Special Purpose M1153, Drill Dummy Inert (DDI) M1156, Blank M1157 and 9MM 135 grain +P law enforcement/Criminal Investigation Division (CID) munition. The Ball cartridge is intended for use
 against enemy personnel, for training, and for force protection. The Special Purpose cartridge is required for use in situations where limited over-penetration of targets is necessary to reduce collateral damage
 in military environments. DDI cartridges are completely inert, plated and drilled for easy identification and used for training and weapon familiarization. Blank cartridges are used for K-9 training through the use
 of a weapon adapter kit. These items are type classified, Code A, approved for service. 9MM 135 grain +P law enforcement cartridge/Criminal Investigation Division (CID) munition is used to further limit over-
 penetration of targets to reduce collateral damage for specific civilian criminal engagements. This item is Code B, not approved for service use.

 (E96105) CTG, 9MM MARKING, M1041 (BLUE) is used for force-on-force training engagements. The cartridge can be fired with existing M9/M11/MHS pistols and M4 rifles with use of a conversion kit. The
 M9 kit consists of a replacement barrel only. The M11 kit consists of a replacement barrel and recoil spring guide. The M4 kit consist of a replacement upper receiver for 9mm. A blue enameled portion of the
 M9, M11, and M4 barrels is visible through the ejection port of the weapons. The projectile leaves a mark upon impact (similar to paintball), enabling after action evaluation of training scenarios. It differs from
 paintball in that it is a full complete cartridge with projectile and cartridge case containing a propulsion system for a low velocity launch. The M1041 is required to hit targets accurately out to 12 meters. The
 cartridge has been safety certified to be fired in close proximity at properly protected human subjects. This item is Code A, approved for service use.

 (E96107) CTG, 9MM MARKING, M1041 (RED) is used for force-on-force training engagements. The cartridge can be fired with existing M9/M11/MHS pistols, and M4 rifles with use of a conversion kit. The M9
 kit consists of a replacement barrel only. The M11 kit consists of a replacement barrel and recoil spring guide. The M4 kit consist of a replacement upper receiver for 9mm. A blue enameled portion of the M9,
 M11 and M4 barrels is visible through the ejection port of the weapons. The projectile leaves a mark upon impact (similar to paintball), enabling after action evaluation of training scenarios. It differs from paintball
 in that it is a full complete cartridge with projectile and cartridge case containing a propulsion system for a low velocity launch. The M1041 is required to hit targets accurately out to 12 meters. The cartridge has
 been safety certified to be fired in close proximity at properly protected human subjects. This item is Code A, approved for service use.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                     Date: April 2026
