INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2034_L005$$, 2026, $$This budget line includes .50 CAL ALL TYPES.

 (E07100) CTG .50 Caliber Cartridge Ball M33 is linked in 100-cartridge belts with the M9 link, for use in the M2, M2A1, and M3 Machine Gun. M33 is identified with a plain bullet tip. This item is Code A, approved
 for service use.

 (E07200) CTG .50 Caliber Cartridge, Ball M33 and Cartridge, Tracer M17 linked 4 to 1 in a 100-cartridge belt with the M9 link for use in M2, M2A1, and M3 Machine Gun against unarmored targets. The tracer
 cartridge permits observation of the bullet's trajectory to the point of impact. M17 is identified with a brown bullet tip. M33 is identified with a plain bullet tip. This item is Code A, approved for service use.

 (E07302) CTG .50 Caliber Blank Cartridge, M1A1 linked in a 100-cartridge belt with the M9 link for use in the M2 and M2A1 Machine Gun. This cartridge is a blank cartridge with a rosette crimp at the mouth used
 to simulate firing in training exercises in conjunction with the M19 Blank Firing Attachment (BFA). This item is Code A, approved for service use.

 (E07307) .50 Caliber Reduced Range Cartridges, XM1181/XM1199, are issued in a 100 cartridge belt with the M9 link for use in the M2 machine gun family. These cartridges are conventional small-caliber
 munitions with a newly designed projectile used for live fire training on ranges with reduced Surface Danger Zones (SDZ). They are intended for training use only and are not suitable for combat. These items are
 Code B, not approved for service use.

 (F88000) .50 Caliber Saboted Light Armor Penetrator (SLAP), M903 cartridge consists of a low-drag, tungsten-alloy penetrator encased in a lightweight plastic sabot loaded into otherwise conventional
 Caliber .50 cartridge components. The projectile assembly is launched at high velocity and the sabot is discarded shortly after muzzle exit. The companion M962 SLAP-Tracer cartridge is similar in configuration
 to the M903 except that the penetrator has a cavity containing tracer mix. The M962 provides the precision of delivery necessary to take full advantage of the penetrator cartridge capability. This ammunition is
 linked to four M903 SLAP to one M962 tracer for use in the M2 Heavy Barrel Machine Gun. The SLAP is used in combat against current and future light armored targets and Armored Attack Helicopters (AAHs).
 The M903 provides the M2 Machine Gun with a more effective capability against improved armored vehicles increasing penetration of light armor by a factor of two to three times at any given range over that of
 currently available ammunition. The item is Code A, approved for service use.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                     Date: April 2026
