INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2034_L029$$, 2026, $$This budget line includes Signals, All Types.

 (E46400) Signal, Hand Held Red Star Cluster M158
 The Family of Hand Held Signals are individually launched pyrotechnics used for signaling and illumination. The payload is launched by a small, fin stabilized rocket and reaches a height of 725 feet. M158 is a
 red star cluster signal used primarily for signaling and illuminating missions. The payload is a cluster of five flares that burn for approximately 10 seconds. This item is Code A, approved for service use.

 (E46500) Signal, Hand Held White Star Cluster M159
 The Family of Hand Held Signals are individually launched pyrotechnics used for signaling and illumination. The payload is launched by a small, fin stabilized rocket and reaches a height of 725 feet. M159 is a
 white star cluster signal used primarily for signaling and illuminating missions. The payload is a cluster of five flares that burn for approximately 10 seconds. This item is Code A, approved for service use.

 E46700 / Signal, Hand Held Red Parachute Flare M126A1 [LA80]
 The M126A1 is a red parachute flare used for nighttime illumination, surface-to-air, and surface -to-ground signaling. The payload is launched by a small fin stabilized rocket and reaches a height of 725 feet. The
 flare burns for approximately 50 seconds. This is a Code A, approved for service use.

 (E46800) Signal, Hand Held White Parachute Flare M127A1
 The Family of Hand Held Signals are individually launched pyrotechnics used for signaling and illumination. The payload is launched by a small, fin stabilized rocket and reaches a height of 725 feet. The
 M127A1 is a white parachute flare used primarily for nighttime battlefield illumination, surface-to-air & surface-to-ground signaling. The flare burns for approximately 50 seconds. This item is Code A, approved
 for service use.

 (E47000) Signal, Hand Held Green Star Cluster M125A1
 The Family of Hand Held Signals are individually launched pyrotechnics used for signaling and illumination. The payload is launched by a small, fin stabilized rocket and reaches a height of 725 feet. M125A1 is
 a green star cluster signal used for signaling and illuminating missions. The payload is a cluster of five flares that burn for approximately 10 seconds. This item is Code A, approved for service use.

 (E48300) Signal, Hand Held Green Parachute Flare M195$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Army                                                                                                                     Date: April 2026
